// src/nodes/deleteNode.js
import React from "react";
import "./node.css";

export const DeleteNode = ({ id, data }) => {
  const handleDelete = () => {
    if (data.onDelete) {
      data.onDelete(id); // delete THIS node itself
    }
  };

  return (
    <div className="vs-node delete-node">
      <div className="vs-node-header">Delete Node</div>
      <p>Click to erase this vertex</p>
      <button onClick={handleDelete}>Delete Me</button>
    </div>
  );
};
